module top_module(
	input reset, left, right, clk,
	output LC, LB, LA, RA, RB, RC
);parameter ST_IDLE = 3'b000;
parameter ST_L1 = 3'b001;
parameter ST_L2 = 3'b010;
parameter ST_L3 = 3'b011;
parameter ST_R1 = 3'b100;
parameter ST_R2 = 3'b101;
parameter ST_R3 = 3'b110;

reg [2:0] obf_state, next_state;

always @(posedge clk)
	if (reset)
		obf_state <= ST_IDLE;
	else
		obf_state <= next_state;

always @*
begin
	case (obf_state)
		ST_IDLE: begin
			if (left && ~right)
				next_state = ST_L1;
			else if (~left && right)
				next_state = ST_R1;
			else
				next_state = ST_IDLE;
		end
		ST_L1: next_state = ST_L2;
		ST_L2: next_state = ST_L3;
		ST_R1: next_state = ST_R2;
		ST_R2: next_state = ST_R3;
		default: next_state = ST_IDLE;
	endcase
	if (left && right)
		next_state = ST_IDLE;

end

assign LA = obf_state == ST_L1 || obf_state == ST_L2 || obf_state == ST_L3;
assign LB = obf_state == ST_L2 || obf_state == ST_L3;
assign LC = obf_state == ST_L3;
assign RA = obf_state == ST_R1 || obf_state == ST_R2 || obf_state == ST_R3;
assign RB = obf_state == ST_R2 || obf_state == ST_R3;
assign RC = obf_state == ST_R3;

endmodule
